import moment from 'moment';
import { call, put, select } from 'redux-saga/effects';

import api from '../../../services/api';
import {
  productsAction,
  productsCallback,
  ProductsResponseData,
} from '../../ducks/customers/products';
import { getCustomerCpf } from './functions';

let RETRIES_COUNT = 3;

export function* productsRequest({
  callback,
  isFromHome,
}: {
  cpf?: string;
  callback: productsCallback;
  isFromHome: boolean;
}) {
  try {
    const cpf: string = yield select(getCustomerCpf);

    if (!cpf) {
      throw new Error('Insufficient information!');
    }

    const response: ProductsResponseData = yield call(
      api.get,
      `/customers/${cpf}/products`,
    );

    const unlockCard = response?.data?.data?.CartaoCredito?.[0]?.Cartoes?.find(
      card => {
        const allowUnlockCard =
          card?.Virtual === false &&
          card?.Bloqueio === true &&
          card?.TipoBloqueio === 'XW' &&
          !!card?.Embossado &&
          card?.MotivoCancelamento === '900';
        return allowUnlockCard;
      },
    );

    if (callback) {
      yield call(callback, {
        statusCode: response.status,
        response: response.data,
      });
    }

    yield put(
      productsAction.productSuccess({
        response: response.data?.data?.CartaoCredito,
        unlockCard: {
          cardNumber: unlockCard?.NrCartao,
          isVisible: !!unlockCard,
          message: moment(unlockCard?.DataAberturaCartao)
            .add(15, 'd')
            .format('DD/MMM/YY'),
        },
      }),
    );
    RETRIES_COUNT = 3;
  } catch (err) {
    if (RETRIES_COUNT > 0) {
      RETRIES_COUNT -= 1;
      yield put(productsAction.productRequest(isFromHome, callback));
      return;
    }
    yield put(productsAction.productError());
  }
}

