import { call, put } from '@redux-saga/core/effects';
import { api } from '@semparar/mf-app-user';
import jwt_decode from 'jwt-decode';
import storage from '~/redux/store/storage';

import { RescueTypes, rescueActions, ResgateResponse } from '../../ducks/rescue';
import { Creators as PointsCreators } from '../../ducks/points';

export function* postRescue({
  data,
}: {
  type: RescueTypes.REQUEST;
  data: {
    payload?: any;
    onSuccess?: (status: ResgateResponse['status']) => void;
    onFailed?: (status?: ResgateResponse['status']) => void;
  };
}) {
  try {
    const accessTokenApp = yield storage.getItem('accessToken');
    let participantId = data?.payload?.participantId;
    try {
      if (!participantId && accessTokenApp) {
        const decoded: any = jwt_decode(accessTokenApp);
        participantId = decoded?.NRC ?? participantId;
      }
    } catch {}

    const payload = {
      ...(data?.payload ?? {}),
      ...(participantId ? { participantId } : {}),
    };

    const url = 'fintech/v1/rewardProgram/rescue';

    try {
      console.log('[RescueSaga][postRescue] Request', { url, payload });
    } catch {}

    const response: { data: any; status?: number; headers?: any; config?: any } = yield call(
      api.post,
      url,
      payload,
    );

    try {
      console.log('[RescueSaga][postRescue] Response', { status: response?.status, data: response?.data });
    } catch {}

    const rawStatus = response?.data?.status ?? response?.data?.data?.status;
    const code = rawStatus?.returnCode ?? rawStatus?.codigoRetorno;

    let treatAsSuccessFromErrorString: ResgateResponse['status'] | undefined;
    try {
      const errorMessageRaw = response?.data?.errorMessage ?? response?.data?.data?.errorMessage;
      if (typeof errorMessageRaw === 'string' && errorMessageRaw.trim().startsWith('{')) {
        const parsed = JSON.parse(errorMessageRaw);
        const st = parsed?.status;
        const msg = String(st?.message ?? '');
        const rc = Number(st?.returnCode ?? st?.codigoRetorno);
        if (rc === -1 && /Internal validation error/i.test(msg)) {
          treatAsSuccessFromErrorString = {
            returnCode: 0,
            message: msg,
            httpStatus: st?.httpStatus,
            error: st?.error,
          } as ResgateResponse['status'];
        }
      }
    } catch {}

    let treatAsSuccessFromKnownMessage: ResgateResponse['status'] | undefined;
    try {
      const msg = String(rawStatus?.message ?? '');
      const httpStatus = response?.status;
      if (httpStatus === 200 && /Erro ao consultar conta/i.test(msg)) {
        treatAsSuccessFromKnownMessage = {
          returnCode: 0,
          message: msg,
          httpStatus: (rawStatus as any)?.httpStatus ?? httpStatus,
          error: (rawStatus as any)?.error,
        } as ResgateResponse['status'];
      }
    } catch {}

    let treatAsSuccessFromSuccessMessage: ResgateResponse['status'] | undefined;
    try {
      const msg = String(rawStatus?.message ?? '');
      const httpStatus = response?.status;
      if (httpStatus === 200 && /^success$/i.test(msg)) {
        treatAsSuccessFromSuccessMessage = {
          returnCode: 0,
          message: msg,
          httpStatus: (rawStatus as any)?.httpStatus ?? httpStatus,
          error: (rawStatus as any)?.error,
        } as ResgateResponse['status'];
      }
    } catch {}

    if (rawStatus && Number(code) === 0) {
      yield put(rescueActions.rescueSuccess({ status: rawStatus }));
      try {
        yield put(PointsCreators.requestPointsBalance());
      } catch {}
      if (typeof data?.onSuccess === 'function') data.onSuccess(rawStatus);
    } else if (treatAsSuccessFromErrorString) {
      yield put(rescueActions.rescueSuccess({ status: treatAsSuccessFromErrorString }));
      try {
        yield put(PointsCreators.requestPointsBalance());
      } catch {}
      if (typeof data?.onSuccess === 'function') data.onSuccess(treatAsSuccessFromErrorString);
    } else if (treatAsSuccessFromKnownMessage) {
      yield put(rescueActions.rescueSuccess({ status: treatAsSuccessFromKnownMessage }));
      try {
        yield put(PointsCreators.requestPointsBalance());
      } catch {}
      if (typeof data?.onSuccess === 'function') data.onSuccess(treatAsSuccessFromKnownMessage);
    } else if (treatAsSuccessFromSuccessMessage) {
      yield put(rescueActions.rescueSuccess({ status: treatAsSuccessFromSuccessMessage }));
      try {
        yield put(PointsCreators.requestPointsBalance());
      } catch {}
      if (typeof data?.onSuccess === 'function') data.onSuccess(treatAsSuccessFromSuccessMessage);
    } else {
      const failedStatus = rawStatus ?? {
        returnCode: -1,
        message: 'Unexpected rescue response',
      };
      yield put(rescueActions.rescueFailed({ status: failedStatus }));
      if (typeof data?.onFailed === 'function') data.onFailed(failedStatus);
    }
  } catch (error) {
    yield put(rescueActions.rescueFailed({ status: undefined }));
    if (typeof data?.onFailed === 'function') data.onFailed(undefined);
  }
}

